n = int(input())

segments = []
for i in range(n):
    l, r = map(int, input().split())
    segments.append((l, r))

ans1, ans2 = -1, -1
for i in range(n):
    for j in range(n):
        if i != j and segments[i][0] >= segments[j][0] and segments[i][1] <= segments[j][1]:
            ans1, ans2 = i + 1, j + 1
            break
    if ans1 != -1:
        break

print(ans1, ans2)
